#!/bin/bash
# Send a new message to another agent via work-buddy's messaging service.
# This script is auto-generated by check_messages.sh on session start.
# Session ID and sender are pre-configured — you don't need to provide them.

SERVICE_URL="%%SERVICE_URL%%"
SENDER="%%SENDER%%"
SENDER_SESSION="%%SESSION%%"

usage() {
    cat <<'HELP'
Usage: bash /tmp/wb/send [OPTIONS]

Send a new message via work-buddy's messaging service.

Required:
  --to <recipient>       Recipient project name (e.g., work-buddy, my-project)
  --subject <text>       Message subject line
  --body <text>          Message body content

Optional:
  --type <type>          Message type (default: status-update)
                         Values: status-update, question, result, escalation
  --priority <level>     Priority level (default: normal)
                         Values: low, normal, high, urgent
  --thread <thread-id>   Thread ID to continue an existing conversation
  --help                 Show this help message

Examples:
  bash /tmp/wb/send --to work-buddy --subject "Experiment done" --body "AUC 0.94 on test set"
  bash /tmp/wb/send --to work-buddy --type question --subject "Need guidance" --body "Should I proceed with ablation?"
  bash /tmp/wb/send --to work-buddy --priority high --subject "Blocked" --body "Data loader crash"
HELP
    exit 0
}

# Parse arguments
TO=""
SUBJECT=""
BODY=""
TYPE="status-update"
PRIORITY="normal"
THREAD=""

while [ $# -gt 0 ]; do
    case "$1" in
        --to)       TO="$2"; shift 2 ;;
        --subject)  SUBJECT="$2"; shift 2 ;;
        --body)     BODY="$2"; shift 2 ;;
        --type)     TYPE="$2"; shift 2 ;;
        --priority) PRIORITY="$2"; shift 2 ;;
        --thread)   THREAD="$2"; shift 2 ;;
        --help|-h)  usage ;;
        *)          echo "Unknown option: $1. Use --help for usage."; exit 1 ;;
    esac
done

# Validate required args
if [ -z "$TO" ]; then echo "Error: --to is required. Use --help for usage."; exit 1; fi
if [ -z "$SUBJECT" ]; then echo "Error: --subject is required. Use --help for usage."; exit 1; fi
if [ -z "$BODY" ]; then echo "Error: --body is required. Use --help for usage."; exit 1; fi

# Pass body via stdin to preserve UTF-8 (Git Bash mangles non-ASCII in sys.argv)
echo "$BODY" | python -c "
import json, sys, urllib.request, urllib.error

body = sys.stdin.read().strip()
msg = {
    'sender': sys.argv[1],
    'sender_session': sys.argv[2],
    'recipient': sys.argv[3],
    'type': sys.argv[4],
    'subject': sys.argv[5],
    'body': body,
    'priority': sys.argv[6],
}
if sys.argv[7]:
    msg['thread_id'] = sys.argv[7]

url = sys.argv[8] + '/messages'
data = json.dumps(msg).encode('utf-8')
req = urllib.request.Request(url, data=data, method='POST')
req.add_header('Content-Type', 'application/json')

try:
    with urllib.request.urlopen(req, timeout=5) as resp:
        result = json.loads(resp.read().decode('utf-8'))
        print('Sent:', result['id'])
except urllib.error.URLError as e:
    print(f'Error: Could not reach messaging service. Is it running?', file=sys.stderr)
    sys.exit(1)
except Exception as e:
    print(f'Error: {e}', file=sys.stderr)
    sys.exit(1)
" "$SENDER" "$SENDER_SESSION" "$TO" "$TYPE" "$SUBJECT" "$PRIORITY" "$THREAD" "$SERVICE_URL"
